var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사람을 공격하지 않는 개체가 있었다고?","JPN":"人間を攻撃しない個体がいただと？","ENG":"There was a C.O. that didn't attack people?","TWN":"你碰到了不會攻擊人的侵蝕體？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そうだ。","ENG":"Yup.","TWN":"是的。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내가 아는 침식체란 건 백이면 백, 살아있는 것만 보면 덤벼드는 짐승 같은 놈들인데…","JPN":"私の知ってる侵食体はみんな、生きてるものを見ると飛びかかる獣のような奴らだが……","ENG":"The C.O.s I know are beast-like creatures that jump at anything alive.","TWN":"我所知道的侵蝕體都是一群見到活物就會攻擊的怪物，毫無例外。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 녀석들은 달랐어. 뭔가에 홀린 것처럼 어딘가로 달려가고 있더라고.","JPN":"あいつらは違った。何かに誘われるように、走っていったんだ。","ENG":"But that one was different. It was running somewhere, like it was drawn by something.","TWN":"但他們卻不同，好像被什麼東西迷住了一樣都朝著一個方向前進。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"침식체가 인간을 무시하다니, 그런 건 들어본 적도 없군.","JPN":"侵食体が人間を無視するなんて、聞いたことがないな。","ENG":"A C.O. ignoring humans? I've never heard of anything like it.","TWN":"侵蝕體略過人類？我從來沒聽說過這種事。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 나도 믿기 힘든 건 이해해. 딱히 증거도 없으니…","JPN":"ま、信じられないのはわかるよ。別に証拠もないし……","ENG":"I understand that it's hard to believe. I don't really have any proof either...","TWN":"我知道這很難讓人相信，也沒有什麼證據……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"Oh?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"컨트롤 쉘터. 현재 샤레이드에 있는 침식체들의 동향을 파악해서 보고하도록.","JPN":"コントロールシェルター。現在シャレードにいる侵食体たちの動向を把握し、報告しろ。","ENG":"Control shelter. Investigate and report on the movement of C.O.s within Charade.","TWN":"庇護所，馬上掌握並報告查雷德內侵蝕體的動向。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"놈들은 아마도 특정 좌표로 향하고 있을 가능성이 높다.","JPN":"奴らはおそらく特定の座標に向かっている可能性が高い。","ENG":"It's likely that they're headed to a certain coordinate.","TWN":"他們很可能是在前往一個特定的座標。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"<color=#ffd34c>네, 알겠습니다. 시니어님.</color>","JPN":"<color=#ffd34c>はい、わかりました。シニア。</color>","ENG":"<color=#ffd34c>Yes, Ms. Senior.</color>","TWN":"<color=#ffd34c>好的，Senior。</color>"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"당신 관리국 시니어였어?!","JPN":"あんた、管理局のシニアだったのか！？","ENG":"You're an Administration Senior?!","TWN":"你是管理局的Senior？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그런데도 3등 시민의 말을 이렇게 쉽게 믿어도 돼?","JPN":"なのに、3等市民の話をこんな簡単に信じちゃっていいの？","ENG":"And you're going to take my word, a grade 3 citizen's word?","TWN":"那你可以如此輕易相信一個三等市民說的話？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어찌됐건 샤레이드의 시민이라면, 자기 집이 무너지길 바라진 않겠지.","JPN":"シャレードの市民なら、自分の家が壊されることを望みはしないだろう。","ENG":"If you're a citizen of Charade, you wouldn't want your home to be destroyed.","TWN":"不管怎樣，身為查雷德的市民總不會希望自己的家園被摧毀吧。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네 사장이 믿을만하다고 했으니, 검증해서 손해 볼 건 없어.","JPN":"お前の社長が信頼できると言っているから、検証して損することはない。","ENG":"Plus, your boss vouched for you, so there's no harm in checking it.","TWN":"你的老闆說你值得信賴，所以證實一下也沒什麼損失。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"추후에 결과가 나오면 알려주겠다.","JPN":"後に結果が出れば知らせてやろう。","ENG":"I'll let you know when I receive news.","TWN":"如果有了結果會告訴你的。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어… 응.","JPN":"うん……わかったよ。","ENG":"Oh... okay.","TWN":"呃……喔。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"무슨 얘길 하다 온 거예요, 라이카?","JPN":"何を話してたの？　ライカ。","ENG":"What were you talking about, Laika?","TWN":"你和他說了什麼，萊卡？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시민 제보.","JPN":"市民からの情報提供。","ENG":"Just reported some information.","TWN":"市民舉報。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};